#!/bin/bash
set -e
cd "$(dirname "$0")"

mkdir -p scripts
python3 -c "import base64; open('scripts/daily-agent.mjs', 'wb').write(base64.b64decode(''))"
echo "✅ scripts/daily-agent.mjs"

mkdir -p scripts
python3 -c "import base64; open('scripts/daily-agent.sh', 'wb').write(base64.b64decode(''))"
echo "✅ scripts/daily-agent.sh"

chmod +x scripts/daily-agent.sh
git add scripts/daily-agent.mjs scripts/daily-agent.sh
git status --short
git commit -m "feat: daily-agent - 毎日3〜5タスクを自律提案・実行するbot"
git push origin main
echo ""
echo "🚀 Push完了！"
echo ""
echo "=== セットアップ ==="
echo ""
echo "① テスト実行（提案のみ）:"
echo "   node scripts/daily-agent.mjs --dry-run"
echo ""
echo "② フル実行（提案+実行+push）:"
echo "   node scripts/daily-agent.mjs"
echo ""
echo "③ cron設定（crontab -e）:"
echo "   毎朝7時に自動実行:"
echo "   0 7 * * * cd ~/Downloads/kyuryo-lab && bash scripts/daily-agent.sh >> scripts/logs/cron.log 2>&1"
echo ""
echo "④ LINE通知を使う場合:"
echo "   .env.local に追加: LINE_TOKEN=<LINEノーティファイのトークン>"
echo ""
echo "=== cronの全設定 ==="
echo "   0 7 * * *     daily-agent（毎日）← NEW"
echo "   0 8 * * 1,4   generate-article（月・木）"
echo "   0 9 * * 0     analyze-and-improve（日曜）"